import React, { useState } from "react";
import axios from "axios";
import Leaderboard from "../Leaderboard";
import "../App.css";

const Predictor = () => {
  const [form, setForm] = useState({
    examScore: 60,
    assignmentScore: 70,
    seminarScore: 65,
    projectScore: 75,
    sportsScore: 20,
    hackathonScore: 15,
    attendance: 85,
  });

  const [result, setResult] = useState(null);
  const [leaderboard, setLeaderboard] = useState([]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: Number(e.target.value) });
  };

  const predict = async () => {
    try {
      const res = await axios.post("http://localhost:5000/predict", form);
      setResult(res.data);
    } catch (error) {
      console.error("Prediction error:", error);
      alert("Prediction service unavailable");
    }
  };

  const loadLeaderboard = async () => {
    try {
      const res = await axios.get("http://localhost:5000/leaderboard");
      setLeaderboard(res.data);
    } catch (error) {
      console.error("Leaderboard error:", error);
    }
  };

  const fields = [
    { name: "examScore", label: "Exam Score (40-100)", min: 40, max: 100 },
    { name: "assignmentScore", label: "Assignment Score (40-100)", min: 40, max: 100 },
    { name: "seminarScore", label: "Seminar Score (30-100)", min: 30, max: 100 },
    { name: "projectScore", label: "Project Score (40-100)", min: 40, max: 100 },
    { name: "sportsScore", label: "Sports Score (0-50)", min: 0, max: 50 },
    { name: "hackathonScore", label: "Hackathon Score (0-50)", min: 0, max: 50 },
    { name: "attendance", label: "Attendance % (50-100)", min: 50, max: 100 },
  ];

  return (
    <div className="container">
      <div className="predictor">
        <h2>🔮 AI Prediction</h2>

        {fields.map((field) => (
          <div key={field.name} className="input-group">
            <label>{field.label}</label>
            <input
              type="range"
              name={field.name}
              min={field.min}
              max={field.max}
              value={form[field.name]}
              onChange={handleChange}
            />
            <span>{form[field.name]}</span>
          </div>
        ))}

        <button className="predict-btn" onClick={predict}>
          🚀 Predict Performance
        </button>

        {result && (
          <div className="result">
            <h3>📊 Predicted Results:</h3>
            <div className="score">
              Score: {result.predictedScore?.toFixed(1)} / 100
            </div>
            <div className={`status ${result.pass ? "pass" : "fail"}`}>
              {result.pass ? "✅ PASS" : "❌ FAIL"}
            </div>
          </div>
        )}
      </div>

      <Leaderboard data={leaderboard} refresh={loadLeaderboard} />
    </div>
  );
};

export default Predictor;
